 31→  | "ready" // 有 script,未跑 pipeline
 32→  | "running" // pipeline 进行中
 33→  | "failed" // 上次 exit !== 0
 34→  | "done"; // 有完整 output
 35→
 36→/** Chunk 工作流状态(对应 chunks.json status 字段) */
 37→export type ChunkStatus =
 38→  | "pending"
 39→  | "synth_done"
 40→  | "transcribed"
 41→  | "failed";
 42→
 43→// ============================================================
 44→// Take (multi-take 支持)
 45→// ============================================================
 46→
 47→/** 一次合成的音频。multi-take 时一个 chunk 可能有多个 take */
 48→export interface Take {
 49→  id: TakeId;
 50→  /** 文件名(相对 .work/<ep>/audio/),不含路径 */
 51→  file: string;
 52→  durationS: number;
 53→  createdAt: string; // ISO ts
 54→  /** 合成参数(temperature/top_p/seed 等),扩展用 */
 55→  params?: Record<string, unknown>;
 56→}
 57→
 58→// ============================================================
 59→// Chunk
 60→// ============================================================
 61→
 62→export interface Chunk {
 63→  id: ChunkId;
 64→  shotId: ShotId;
 65→  /** 在 shot 内的序号(从 1 开始) */
 66→  index: number;
 67→
 68→  // —— 三个文本字段 ——
 69→  /** 原文(P1 切分后,只读参考) */
 70→  text: string;
 71→  /** TTS 朗读用,改了触发 P2/P3/P5/P6 */
 72→  textNormalized: string;
 73→  /** 字幕显示用(可选),改了只触发 P5/P6 */
 74→  subtitleText: string | null;
 75→
 76→  // —— 状态与产物 ——
 77→  status: ChunkStatus;
 78→  /** 全部 take 列表(MVP 大多 chunk 只有 1 个) */
 79→  takes: Take[];
 80→  /** 当前生效的 take id;P5/P6 拼接时使用 */
 81→  selectedTakeId: TakeId | null;
 82→
 83→  // —— 元信息 ——
 84→  charCount: number;
 85→  /** 边界 hash(由 shotId + index + text 计算,变了 → 失效下游) */
 86→  boundaryHash?: string;
 87→
 88→  /** 扩展位:任何 adapter 想多带的信息塞这里 */
 89→  metadata: Record<string, unknown>;
 90→}
 91→
 92→// ============================================================
 93→// Episode
 94→// ============================================================
 95→
 96→export interface Episode {
 97→  id: EpisodeId;
 98→  status: EpisodeStatus;
 99→  /** 当前 stage 的 opaque 描述,前端只显示不解析 */
100→  currentStage: string | null;
101→  /** 全部 chunks(读详情时返回) */
102→  chunks: Chunk[];
103→  /** 全部 chunk 时长之和 */
104→  totalDurationS: number;
105→  createdAt: string;
106→  updatedAt: string;
107→  metadata: Record<string, unknown>;
108→}
109→
110→/** 列表项,无 chunks(给 sidebar 用) */
111→export interface EpisodeSummary {
112→  id: EpisodeId;
113→  status: EpisodeStatus;
114→  currentStage: string | null;
115→  chunkCount: number;
116→  updatedAt: string;
117→}
118→
119→// ============================================================
120→// Edits / Apply
121→// ============================================================
122→
123→/** 单个 chunk 的编辑。两个字段都可选,只填想改的 */
124→export interface ChunkEdit {
125→  /** 改了 → 触发 P2 + P3 + P5 + P6 */
126→  textNormalized?: string;
127→  /** 改了 → 只触发 P5 + P6 */
128→  subtitleText?: string;
129→}
130→
131→/** 批量 Apply 的载荷 */
132→export type EditBatch = Record<ChunkId, ChunkEdit>;
133→
134→// ============================================================
135→// Job / Operation
136→// ============================================================
137→
138→/** PipelineRunner 的所有方法都返回这个,代表"已开始执行" */
139→export interface OperationResult {
140→  jobId: JobId;
141→  startedAt: string;
142→}
143→
144→export type JobState =
145→  | "queued"
146→  | "running"
147→  | "done"
148→  | "failed"
149→  | "canceled";
150→
151→export interface JobStatus {
152→  id: JobId;
153→  state: JobState;
154→  startedAt: string;
155→  finishedAt: string | null;
156→  exitCode: number | null;
157→  error: string | null;
158→  /** 如果属于某个 episode */
159→  episodeId?: EpisodeId;
160→}
161→
162→// ============================================================
163→// Errors
164→// ============================================================
165→
166→/** Adapter / Domain 层抛错时,给 Route Handler 转 HTTP code 用 */
167→export class DomainError extends Error {
168→  constructor(
169→    message: string,
170→    public code:
171→      | "not_found"
172→      | "lock_busy"
173→      | "invalid_state"
174→      | "invalid_input"
175→      | "internal",
176→    public details?: unknown,
177→  ) {
