 1→/**
 2→ * LockManager port — 三 scope 锁
 3→ *
 4→ * scope 设计:
 5→ *   global  : 占用 P3 sidecar(整集 run / Apply / finalize)
 6→ *   episode : 同一 episode 内的串行(预留,MVP 不用)
 7→ *   chunk   : 同一 chunk 不能同时 retry × 2(multi-take 并发用)
 8→ *
 9→ * 不冲突规则:
10→ *   global   ←→  episode/chunk : 互斥
11→ *   episode  ←→  其他 episode    : 不互斥
12→ *   chunk    ←→  其他 chunk     : 不互斥(允许并行)
13→ *   chunk    ←→  同 chunk        : 互斥
14→ *
15→ * MVP 实现: InMemoryLockManager(单进程 Map)
16→ * 未来扩展: RedisLockManager(多进程)
17→ */
18→
19→import type { ChunkId, EpisodeId } from "../types";
20→
21→export type LockScope =
22→  | { type: "global" }
23→  | { type: "episode"; episodeId: EpisodeId }
24→  | { type: "chunk"; episodeId: EpisodeId; chunkId: ChunkId };
25→
26→export interface LockManager {
27→  /**
28→   * 取得锁。
29→   * 失败抛 LockBusyError。
30→   */
31→  acquire(scope: LockScope, owner: string): Promise<LockHandle>;
32→
33→  /** 检查是否被占用(不抢) */
34→  isBusy(scope: LockScope): Promise<boolean>;
35→
36→  /** 列出当前所有持有的锁(debug 用) */
37→  list(): Promise<LockInfo[]>;
38→}
39→
40→export interface LockHandle {
41→  release(): Promise<void>;
42→}
43→
44→export interface LockInfo {
45→  scope: LockScope;
46→  owner: string;
47→  acquiredAt: string;
48→}
49→
50→export class LockBusyError extends Error {
51→  constructor(
52→    public scope: LockScope,
53→    public heldBy: LockInfo,
54→  ) {
55→    super(
56→      `Lock busy: ${JSON.stringify(scope)} (held by ${heldBy.owner} since ${heldBy.acquiredAt})`,
57→    );
58→    this.name = "LockBusyError";
59→  }
60→}
