/**
 * In-memory lock manager with three scopes (global / episode / chunk).
 */
import type {
  LockHandle,
  LockInfo,
  LockManager,
  LockScope,
} from "@/lib/ports";
import { LockBusyError } from "@/lib/ports";

function serialize(scope: LockScope): string {
  switch (scope.type) {
    case "global":
      return "global";
    case "episode":
      return `ep:${scope.episodeId}`;
    case "chunk":
      return `chunk:${scope.episodeId}:${scope.chunkId}`;
  }
}

export class InMemoryLockManager implements LockManager {
  private locks = new Map<string, LockInfo>();

  async acquire(scope: LockScope, owner: string): Promise<LockHandle> {
    // Any lock blocks when global is held
    const globalInfo = this.locks.get("global");
    if (globalInfo) throw new LockBusyError(scope, globalInfo);

    if (scope.type === "global") {
      // Global can't coexist with anything
      const first = this.locks.values().next();
      if (!first.done) throw new LockBusyError(scope, first.value);
    } else if (scope.type === "episode") {
      const epKey = `ep:${scope.episodeId}`;
      if (this.locks.has(epKey)) {
        throw new LockBusyError(scope, this.locks.get(epKey)!);
      }
      // Any chunk lock in same episode blocks episode lock
      for (const [k, v] of this.locks) {
        if (k.startsWith(`chunk:${scope.episodeId}:`)) {
          throw new LockBusyError(scope, v);
        }
      }
    } else {
      // chunk
      const epKey = `ep:${scope.episodeId}`;
      if (this.locks.has(epKey)) {
        throw new LockBusyError(scope, this.locks.get(epKey)!);
      }
      const key = serialize(scope);
      if (this.locks.has(key)) {
        throw new LockBusyError(scope, this.locks.get(key)!);
      }
    }

    const key = serialize(scope);
    const info: LockInfo = {
      scope,
      owner,
      acquiredAt: new Date().toISOString(),
    };
    this.locks.set(key, info);

    return {
      release: async () => {
        this.locks.delete(key);
      },
    };
  }

  async isBusy(scope: LockScope): Promise<boolean> {
    if (this.locks.has("global")) return true;
    if (scope.type === "global") {
      return this.locks.size > 0;
    }
    if (scope.type === "episode") {
      if (this.locks.has(`ep:${scope.episodeId}`)) return true;
      for (const k of this.locks.keys()) {
        if (k.startsWith(`chunk:${scope.episodeId}:`)) return true;
      }
      return false;
    }
    // chunk
    if (this.locks.has(`ep:${scope.episodeId}`)) return true;
    return this.locks.has(serialize(scope));
  }

  async list(): Promise<LockInfo[]> {
    return [...this.locks.values()];
  }
}

/**
 * Progress / log observability — parses run.log and .running flag.
 */
import * as fs from "fs";

import type { LogTailer, ProgressSource } from "@/lib/ports";
import type { EpisodeId } from "@/lib/types";

import { runLogPath, runningFlagPath } from "./paths";

export class StdoutProgressSource implements ProgressSource {
  async getCurrentStage(epId: EpisodeId): Promise<string | null> {
    const p = runLogPath(epId);
    if (!fs.existsSync(p)) return null;
    const buf = fs.readFileSync(p, "utf-8");
    const lines = buf.split("\n");
    for (let i = lines.length - 1; i >= 0; i--) {
      const m = lines[i].match(/=== ([^=]+) ===/);
      if (m) return m[1].trim();
    }
    return null;
  }

  async isRunning(epId: EpisodeId): Promise<boolean> {
    return fs.existsSync(runningFlagPath(epId));
  }
}

export class FileLogTailer implements LogTailer {
  async tail(epId: EpisodeId, lines: number): Promise<string[]> {
    const p = runLogPath(epId);
    if (!fs.existsSync(p)) return [];
    const buf = fs.readFileSync(p, "utf-8");
    const all = buf.split("\n");
    return all.slice(-lines);
  }

  async clear(epId: EpisodeId): Promise<void> {
    const p = runLogPath(epId);
    if (fs.existsSync(p)) fs.writeFileSync(p, "");
  }
}

/**
 * File services — audio / preview / export
 */
import * as fs from "fs";
import * as path from "path";

import type {
  AudioService,
  ChunkStore,
  ExportResult,
  ExportService,
  PreviewService,
} from "@/lib/ports";
import type { ChunkId, EpisodeId, ShotId, TakeId } from "@/lib/types";
import { DomainError } from "@/lib/types";

import {
  audioDir,
  outputDir,
  previewPath,
  workDir,
} from "./paths";

export class LegacyAudioService implements AudioService {
  constructor(private chunks: ChunkStore) {}

  async getTakeFile(
    epId: EpisodeId,
    cid: ChunkId,
    takeId?: TakeId,
  ): Promise<string> {
    const chunk = await this.chunks.get(epId, cid);
    if (!chunk) {
      throw new DomainError(`chunk ${cid} not found`, "not_found");
    }
    const tid = takeId ?? chunk.selectedTakeId;
    if (!tid) {
      throw new DomainError(
        `no take selected for chunk ${cid}`,
        "not_found",
      );
    }
    const take = chunk.takes.find((t) => t.id === tid);
    if (!take) {
      throw new DomainError(`take ${tid} not found`, "not_found");
    }
    const filePath = path.join(audioDir(epId), take.file);
    if (!fs.existsSync(filePath)) {
      throw new DomainError(
        `audio file missing: ${filePath}`,
        "not_found",
      );
    }
    return filePath;
  }

  async getShotFile(epId: EpisodeId, shotId: ShotId): Promise<string> {
    const od = outputDir(epId);
    const candidate = path.join(od, `${shotId}.wav`);
    if (!fs.existsSync(candidate)) {
      throw new DomainError(
        `shot file missing: ${candidate}`,
        "not_found",
      );
    }
    return candidate;
  }
}

export class LegacyPreviewService implements PreviewService {
  async getPreviewFile(epId: EpisodeId): Promise<string> {
    const p = previewPath(epId);
    if (!fs.existsSync(p)) {
      throw new DomainError(`preview not found: ${p}`, "not_found");
    }
    return p;
  }
}

export class LegacyExportService implements ExportService {
  async exportTo(
    epId: EpisodeId,
    targetDir: string,
  ): Promise<ExportResult> {
    if (!targetDir) {
      throw new DomainError("targetDir required", "invalid_input");
    }
    fs.mkdirSync(targetDir, { recursive: true });

    let filesCopied = 0;
    let totalBytes = 0;

    const copyFile = (src: string, dst: string) => {
      fs.copyFileSync(src, dst);
      filesCopied++;
      totalBytes += fs.statSync(dst).size;
    };

    const od = outputDir(epId);
    if (fs.existsSync(od)) {
      for (const name of fs.readdirSync(od)) {
        if (name.endsWith(".wav")) {
          copyFile(path.join(od, name), path.join(targetDir, name));
        }
      }
      const durations = path.join(od, "durations.json");
      if (fs.existsSync(durations)) {
        copyFile(durations, path.join(targetDir, "durations.json"));
      }
    }

    const subs = path.join(workDir(epId), "subtitles.json");
    if (fs.existsSync(subs)) {
      copyFile(subs, path.join(targetDir, "subtitles.json"));
    }

    return { filesCopied, totalBytes };
  }
}

/**
 * LegacyPipelineRunner — spawns run.sh and individual pipeline scripts.
 */
import { spawn, execSync, type ChildProcess } from "child_process";
import * as crypto from "crypto";
import * as fs from "fs";
import * as path from "path";

import type {
  ChunkStore,
  LockHandle,
  LockManager,
  PipelineRunner,
} from "@/lib/ports";
import type {
  ChunkId,
  EditBatch,
  EpisodeId,
  JobId,
  JobStatus,
  OperationResult,
} from "@/lib/types";
import { DomainError } from "@/lib/types";

import {
  audioDir,
  chunksPath,
  findRoot,
  lastExitPath,
  runLogPath,
  runningFlagPath,
  workDir,
} from "./paths";

interface Job {
  id: JobId;
  episodeId: EpisodeId;
  startedAt: string;
  finishedAt: string | null;
  exitCode: number | null;
  error: string | null;
  child: ChildProcess | null;
}

export class LegacyPipelineRunner implements PipelineRunner {
  private jobs = new Map<JobId, Job>();

  constructor(
    private chunks: ChunkStore,
    private locks: LockManager,
  ) {}

  // ────────────────────────────────────────────────
  // spawn helper
  // ────────────────────────────────────────────────

  private spawnAndWait(
    cmd: string,
    args: string[],
    logFile: string,
  ): Promise<number> {
    return new Promise((resolve, reject) => {
      const root = findRoot();
      const child = spawn(cmd, args, { cwd: root, env: process.env });
      child.stdout.on("data", (d) => {
        try {
          fs.appendFileSync(logFile, d);
        } catch {}
      });
      child.stderr.on("data", (d) => {
        try {
          fs.appendFileSync(logFile, d);
        } catch {}
      });
      child.on("exit", (code) => resolve(code ?? -1));
      child.on("error", (err) => reject(err));
    });
  }

  private prepareWork(epId: EpisodeId): {
    wd: string;
    runningFile: string;
    lastExit: string;
    logFile: string;
  } {
    const wd = workDir(epId);
    fs.mkdirSync(wd, { recursive: true });
    const runningFile = runningFlagPath(epId);
    const lastExit = lastExitPath(epId);
    const logFile = runLogPath(epId);
    fs.writeFileSync(runningFile, "");
    if (fs.existsSync(lastExit)) fs.unlinkSync(lastExit);
    return { wd, runningFile, lastExit, logFile };
  }

  private finalize(
    job: Job,
    runningFile: string,
    lastExit: string,
    code: number,
    handle: LockHandle,
    error?: string,
  ) {
    try {
      if (fs.existsSync(runningFile)) fs.unlinkSync(runningFile);
    } catch {}
    try {
      fs.writeFileSync(lastExit, String(code));
    } catch {}
    job.exitCode = code;
    job.finishedAt = new Date().toISOString();
    if (error) job.error = error;
    handle.release().catch(() => undefined);
  }

  // ────────────────────────────────────────────────
  // runFull
  // ────────────────────────────────────────────────

  async runFull(
    epId: EpisodeId,
    _options?: { mode?: "fresh" | "text-only"; force?: boolean },
  ): Promise<OperationResult> {
    const handle = await this.locks.acquire(
      { type: "global" },
      `runFull:${epId}`,
    );
    const { runningFile, lastExit, logFile } = this.prepareWork(epId);

    const jobId = crypto.randomUUID();
    const startedAt = new Date().toISOString();
    const job: Job = {
      id: jobId,
      episodeId: epId,
      startedAt,
      finishedAt: null,
      exitCode: null,
      error: null,
      child: null,
    };
    this.jobs.set(jobId, job);

    const root = findRoot();
    const scriptRel = `episodes/${epId}.json`;

    try {
      const child = spawn("bash", ["run.sh", scriptRel, epId], {
        cwd: root,
        env: process.env,
      });
      job.child = child;
      child.stdout.on("data", (d) => {
        try {
          fs.appendFileSync(logFile, d);
        } catch {}
      });
      child.stderr.on("data", (d) => {
        try {
          fs.appendFileSync(logFile, d);
        } catch {}
      });
      child.on("exit", (code) => {
        this.finalize(job, runningFile, lastExit, code ?? -1, handle);
      });
      child.on("error", (err) => {
        this.finalize(
          job,
          runningFile,
          lastExit,
          -1,
          handle,
          err.message,
        );
      });
    } catch (err) {
      this.finalize(
        job,
        runningFile,
        lastExit,
        -1,
        handle,
        (err as Error).message,
      );
      throw err;
    }

    return { jobId, startedAt };
  }

  // ────────────────────────────────────────────────
  // applyEdits
  // ────────────────────────────────────────────────

  async applyEdits(
    epId: EpisodeId,
    edits: EditBatch,
  ): Promise<OperationResult> {
    const handle = await this.locks.acquire(
      { type: "global" },
      `applyEdits:${epId}`,
    );
    const { runningFile, lastExit, logFile } = this.prepareWork(epId);

    const jobId = crypto.randomUUID();
    const startedAt = new Date().toISOString();
    const job: Job = {
      id: jobId,
      episodeId: epId,
      startedAt,
      finishedAt: null,
      exitCode: null,
      error: null,
      child: null,
    };
    this.jobs.set(jobId, job);

    // 1. Write chunks.json (awaited synchronously before async pipeline)
    try {
      await this.chunks.applyEdits(epId, edits);
    } catch (e) {
      this.finalize(
        job,
        runningFile,
        lastExit,
        -1,
        handle,
        (e as Error).message,
      );
      throw e;
    }

    const hasTtsDirty = Object.values(edits).some(
      (e) => e.textNormalized !== undefined,
    );

    // 2. Run async
    (async () => {
      try {
        const wd = workDir(epId);
        if (hasTtsDirty) {
          fs.appendFileSync(logFile, `\n=== Apply P2 ===\n`);
          const c2 = await this.spawnAndWait(
            "node",
            [
              "scripts/p2-synth.js",
              "--chunks",
              chunksPath(epId),
              "--outdir",
              audioDir(epId),
              "--trace",
              path.join(wd, "trace.jsonl"),
            ],
            logFile,
          );
          if (c2 !== 0) throw new Error(`p2 exit ${c2}`);

          fs.appendFileSync(logFile, `\n=== Apply P3 ===\n`);
          const c3 = await this.spawnAndWait(
            "python",
            [
              "scripts/p3-transcribe.py",
              "--chunks",
              chunksPath(epId),
              "--audiodir",
              audioDir(epId),
              "--outdir",
              path.join(wd, "transcripts"),
              "--server-url",
              "http://127.0.0.1:5555",
            ],
            logFile,
          );
          if (c3 !== 0) throw new Error(`p3 exit ${c3}`);
        }
        fs.appendFileSync(logFile, `\n=== Apply P5/P6 ===\n`);
        const c5 = await this.spawnAndWait(
          "bash",
          ["run.sh", `episodes/${epId}.json`, epId, "--from", "p5"],
          logFile,
        );
        if (c5 !== 0) throw new Error(`run.sh --from p5 exit ${c5}`);

        this.finalize(job, runningFile, lastExit, 0, handle);
      } catch (e) {
        fs.appendFileSync(
          logFile,
          `\n[apply] ERROR: ${(e as Error).message}\n`,
        );
        this.finalize(
          job,
          runningFile,
          lastExit,
          -1,
          handle,
          (e as Error).message,
        );
      }
    })();

    return { jobId, startedAt };
  }

  // ────────────────────────────────────────────────
  // retryChunk
  // ────────────────────────────────────────────────

  async retryChunk(
    epId: EpisodeId,
    cid: ChunkId,
    options: { count: number; params?: Record<string, unknown> },
  ): Promise<OperationResult> {
    const handle = await this.locks.acquire(
      { type: "chunk", episodeId: epId, chunkId: cid },
      `retry:${cid}`,
    );

    const chunk = await this.chunks.get(epId, cid);
    if (!chunk) {
      handle.release().catch(() => undefined);
      throw new DomainError(`chunk ${cid} not found`, "not_found");
    }

    const wd = workDir(epId);
    fs.mkdirSync(wd, { recursive: true });
    fs.mkdirSync(audioDir(epId), { recursive: true });
    const runningFile = runningFlagPath(epId);
    const lastExit = lastExitPath(epId);
    const logFile = runLogPath(epId);
    // retry does NOT clear lastExit (it's a side operation)
    fs.writeFileSync(runningFile, "");

    const jobId = crypto.randomUUID();
    const startedAt = new Date().toISOString();
    const job: Job = {
      id: jobId,
      episodeId: epId,
      startedAt,
      finishedAt: null,
      exitCode: null,
      error: null,
      child: null,
    };
    this.jobs.set(jobId, job);

    (async () => {
      try {
        for (let i = 0; i < options.count; i++) {
          const takeId = `take_${Date.now()}_${i}`;
          const tmpChunksPath = path.join(
            wd,
            `chunks-retry-${takeId}.json`,
          );
          const tmpAudioDir = path.join(wd, `audio-retry-${takeId}`);
          fs.mkdirSync(tmpAudioDir, { recursive: true });

          const tmpChunk = {
            id: chunk.id,
            shot_id: chunk.shotId,
            text: chunk.text,
            text_normalized: chunk.textNormalized,
            char_count: chunk.charCount,
            status: "pending" as const,
          };
          fs.writeFileSync(tmpChunksPath, JSON.stringify([tmpChunk]));

          fs.appendFileSync(logFile, `\n=== Retry ${cid} #${i + 1} ===\n`);
          const code = await this.spawnAndWait(
            "node",
            [
              "scripts/p2-synth.js",
              "--chunks",
              tmpChunksPath,
              "--outdir",
              tmpAudioDir,
              "--chunk",
              cid,
            ],
            logFile,
          );
          if (code !== 0) {
            fs.appendFileSync(
              logFile,
              `\n[retry] ${takeId} failed (exit ${code})\n`,
            );
            try {
              fs.unlinkSync(tmpChunksPath);
            } catch {}
            try {
              fs.rmSync(tmpAudioDir, { recursive: true, force: true });
            } catch {}
            continue;
          }

          // candidate wav filenames: p2-synth writes <cid>.wav or similar.
          // Pick first .wav we find in tmpAudioDir to be robust.
          let srcWav = path.join(tmpAudioDir, `${cid}.wav`);
          if (!fs.existsSync(srcWav)) {
            const wavs = fs
              .readdirSync(tmpAudioDir)
              .filter((f) => f.endsWith(".wav"));
            if (wavs.length === 0) {
              fs.appendFileSync(
                logFile,
                `\n[retry] ${takeId} no wav produced\n`,
              );
              continue;
            }
            srcWav = path.join(tmpAudioDir, wavs[0]);
          }

          const dstFile = `${cid}.${takeId}.wav`;
          const dstPath = path.join(audioDir(epId), dstFile);
          fs.renameSync(srcWav, dstPath);

          let durationS = 0;
          try {
            const out = execSync(
              `ffprobe -v quiet -show_entries format=duration -of csv=p=0 "${dstPath}"`,
              { encoding: "utf-8" },
            );
            durationS = parseFloat(out.trim()) || 0;
          } catch {}

          await this.chunks.appendTake(epId, cid, {
            id: takeId,
            file: dstFile,
            durationS,
            createdAt: new Date().toISOString(),
            params: options.params,
          });

          try {
            fs.unlinkSync(tmpChunksPath);
          } catch {}
          try {
            fs.rmSync(tmpAudioDir, { recursive: true, force: true });
          } catch {}
        }
        try {
          if (fs.existsSync(runningFile)) fs.unlinkSync(runningFile);
        } catch {}
        job.exitCode = 0;
        job.finishedAt = new Date().toISOString();
        handle.release().catch(() => undefined);
      } catch (e) {
        fs.appendFileSync(
          logFile,
          `\n[retry] ERROR: ${(e as Error).message}\n`,
        );
        try {
          if (fs.existsSync(runningFile)) fs.unlinkSync(runningFile);
        } catch {}
        try {
          fs.writeFileSync(lastExit, "-1");
        } catch {}
        job.exitCode = -1;
        job.finishedAt = new Date().toISOString();
        job.error = (e as Error).message;
        handle.release().catch(() => undefined);
      }
    })();

    return { jobId, startedAt };
  }

  // ────────────────────────────────────────────────
  // finalizeTake
  // ────────────────────────────────────────────────

  async finalizeTake(
    epId: EpisodeId,
    cid: ChunkId,
  ): Promise<OperationResult> {
    const handle = await this.locks.acquire(
      { type: "global" },
      `finalize:${cid}`,
    );
    const { runningFile, lastExit, logFile } = this.prepareWork(epId);

    const chunk = await this.chunks.get(epId, cid);
    if (!chunk) {
      this.locks.acquire; // no-op
      handle.release().catch(() => undefined);
      throw new DomainError(`chunk ${cid} not found`, "not_found");
    }

    const jobId = crypto.randomUUID();
    const startedAt = new Date().toISOString();
    const job: Job = {
      id: jobId,
      episodeId: epId,
      startedAt,
      finishedAt: null,
      exitCode: null,
      error: null,
      child: null,
    };
    this.jobs.set(jobId, job);

    (async () => {
      try {
        const wd = workDir(epId);
        fs.appendFileSync(logFile, `\n=== Finalize P3 ${cid} ===\n`);
        const c3 = await this.spawnAndWait(
          "python",
          [
            "scripts/p3-transcribe.py",
            "--chunks",
            chunksPath(epId),
            "--audiodir",
            audioDir(epId),
            "--outdir",
            path.join(wd, "transcripts"),
            "--server-url",
            "http://127.0.0.1:5555",
            "--chunk",
            cid,
          ],
          logFile,
        );
        if (c3 !== 0) throw new Error(`p3 exit ${c3}`);

        fs.appendFileSync(logFile, `\n=== Finalize P5/P6 ===\n`);
        const c5 = await this.spawnAndWait(
          "bash",
          ["run.sh", `episodes/${epId}.json`, epId, "--from", "p5"],
          logFile,
        );
        if (c5 !== 0) throw new Error(`run.sh --from p5 exit ${c5}`);

        this.finalize(job, runningFile, lastExit, 0, handle);
      } catch (e) {
        fs.appendFileSync(
          logFile,
          `\n[finalize] ERROR: ${(e as Error).message}\n`,
        );
        this.finalize(
          job,
          runningFile,
          lastExit,
          -1,
          handle,
          (e as Error).message,
        );
      }
    })();

    return { jobId, startedAt };
  }

  // ────────────────────────────────────────────────
  // cancel / getJobStatus
  // ────────────────────────────────────────────────

  async cancel(jobId: JobId): Promise<void> {
    const job = this.jobs.get(jobId);
    if (!job) return;
    if (job.child && typeof job.child.kill === "function") {
      try {
        job.child.kill("SIGTERM");
      } catch {}
    }
  }

  async getJobStatus(jobId: JobId): Promise<JobStatus> {
    const job = this.jobs.get(jobId);
    if (!job) {
      throw new DomainError(`job ${jobId} not found`, "not_found");
    }
    let state: JobStatus["state"];
    if (job.exitCode === null) state = "running";
    else if (job.exitCode === 0) state = "done";
    else state = "failed";
    return {
      id: job.id,
      state,
      startedAt: job.startedAt,
      finishedAt: job.finishedAt,
      exitCode: job.exitCode,
      error: job.error,
      episodeId: job.episodeId,
    };
  }
}

/**
 * Legacy adapter re-exports.
 * factory.ts imports from here.
 */
export { LegacyEpisodeStore, LegacyChunkStore } from "./store";
export { InMemoryLockManager } from "./lock";
export { StdoutProgressSource, FileLogTailer } from "./observability";
export {
  LegacyAudioService,
  LegacyPreviewService,
  LegacyExportService,
} from "./files";
export { LegacyPipelineRunner } from "./runner";

/**
 * Service factory — sole place adapters are wired.
 *
 * Route Handlers call getServices() to obtain singleton instances.
 * Swapping adapters (e.g. SQLite or Node orchestrator) only touches this file.
 */

import type {
  AudioService,
  ChunkStore,
  EpisodeStore,
  ExportService,
  LockManager,
  LogTailer,
  PipelineRunner,
  PreviewService,
  ProgressSource,
} from "./ports";

import {
  FileLogTailer,
  InMemoryLockManager,
  LegacyAudioService,
  LegacyChunkStore,
  LegacyEpisodeStore,
  LegacyExportService,
  LegacyPipelineRunner,
  LegacyPreviewService,
  StdoutProgressSource,
} from "./adapters/legacy";

export interface Services {
  episodes: EpisodeStore;
  chunks: ChunkStore;
  runner: PipelineRunner;
  locks: LockManager;
  progress: ProgressSource;
  logs: LogTailer;
  audio: AudioService;
  preview: PreviewService;
  export: ExportService;
}

let _services: Services | null = null;

/** Singleton accessor — all Route Handlers use this. */
export function getServices(): Services {
  if (_services) return _services;

  const locks = new InMemoryLockManager();
  const chunks = new LegacyChunkStore();
  const episodes = new LegacyEpisodeStore(chunks);
  const logs = new FileLogTailer();
  const progress = new StdoutProgressSource();
  const runner = new LegacyPipelineRunner(chunks, locks);
  const audio = new LegacyAudioService(chunks);
  const preview = new LegacyPreviewService();
  const exportSvc = new LegacyExportService();

  _services = {
    episodes,
    chunks,
    runner,
    locks,
    progress,
    logs,
    audio,
    preview,
    export: exportSvc,
  };

  return _services;
}

/** Test helper — replace or reset the singleton. */
export function _resetServices(services?: Services): void {
  _services = services ?? null;
}

/**
 * Shared HTTP helpers for Route Handlers.
 *
 * This file lives under app/api so it is NOT an adapter import.
 * (Verifier check: `grep '@/lib/adapters' web/app/api` should be empty.)
 */
import { LockBusyError } from "@/lib/ports";
import { DomainError } from "@/lib/types";

export function handleError(e: unknown): Response {
  if (e instanceof LockBusyError) {
    return new Response(JSON.stringify({ error: "busy", details: e.message }), {
      status: 409,
      headers: { "content-type": "application/json" },
    });
  }
  if (e instanceof DomainError) {
    const status =
      e.code === "not_found"
        ? 404
        : e.code === "lock_busy"
          ? 409
          : e.code === "invalid_input" || e.code === "invalid_state"
            ? 400
            : 500;
    return new Response(
      JSON.stringify({ error: e.code, message: e.message }),
      { status, headers: { "content-type": "application/json" } },
    );
  }
  // eslint-disable-next-line no-console
  console.error("[route]", e);
  return new Response(
    JSON.stringify({ error: "internal", message: (e as Error)?.message ?? "error" }),
    { status: 500, headers: { "content-type": "application/json" } },
  );
}

import { getServices } from "@/lib/factory";
import { handleError } from "../_http";

export async function GET() {
  try {
    const { episodes } = getServices();
    const list = await episodes.list();
    return Response.json({ episodes: list });
  } catch (e) {
    return handleError(e);
  }
}

export async function POST(request: Request) {
  try {
    const { episodes } = getServices();
    const contentType = request.headers.get("content-type") ?? "";

    let id: string | null = null;
    let scriptJson: unknown = null;

    if (contentType.includes("multipart/form-data")) {
      const form = await request.formData();
      id = (form.get("id") as string | null) ?? null;
      const file = form.get("script") as File | null;
      if (!file) {
        return new Response(
          JSON.stringify({ error: "invalid_input", message: "script file required" }),
          { status: 400, headers: { "content-type": "application/json" } },
        );
      }
      const text = await file.text();
      scriptJson = JSON.parse(text);
    } else {
      const body = await request.json();
      id = body.id;
      scriptJson = body.script;
    }

    if (!id) {
      return new Response(
        JSON.stringify({ error: "invalid_input", message: "id required" }),
        { status: 400, headers: { "content-type": "application/json" } },
      );
    }

    const ep = await episodes.create(id, scriptJson);
    return Response.json({ episode: ep }, { status: 201 });
  } catch (e) {
    return handleError(e);
  }
}

import { getServices } from "@/lib/factory";
import { handleError } from "../../_http";

export async function GET(
  _req: Request,
  { params }: { params: Promise<{ id: string }> },
) {
  try {
    const { id } = await params;
    const { episodes, logs, progress } = getServices();
    const ep = await episodes.get(id);
    if (!ep) {
      return new Response(
        JSON.stringify({ error: "not_found" }),
        { status: 404, headers: { "content-type": "application/json" } },
      );
    }
    const [logTail, running, currentStage] = await Promise.all([
      logs.tail(id, 100),
      progress.isRunning(id),
      progress.getCurrentStage(id),
    ]);
    return Response.json({
      episode: { ...ep, currentStage },
      logTail,
      running,
      currentStage,
    });
  } catch (e) {
    return handleError(e);
  }
}

import { getServices } from "@/lib/factory";
import { handleError } from "../../../_http";

export async function POST(
  request: Request,
  { params }: { params: Promise<{ id: string }> },
) {
  try {
    const { id } = await params;
    const { runner } = getServices();
    let options: { mode?: "fresh" | "text-only"; force?: boolean } | undefined;
    try {
      options = await request.json();
    } catch {
      options = undefined;
    }
    const result = await runner.runFull(id, options);
    return Response.json(result);
  } catch (e) {
    return handleError(e);
  }
}

import { getServices } from "@/lib/factory";
import type { EditBatch } from "@/lib/types";
import { handleError } from "../../../_http";

export async function POST(
  request: Request,
  { params }: { params: Promise<{ id: string }> },
) {
  try {
    const { id } = await params;
    const { runner } = getServices();
    const body = await request.json();
    const edits: EditBatch = (body?.edits ?? body) as EditBatch;
    if (!edits || typeof edits !== "object") {
      return new Response(
        JSON.stringify({ error: "invalid_input", message: "edits required" }),
        { status: 400, headers: { "content-type": "application/json" } },
      );
    }
    const result = await runner.applyEdits(id, edits);
    return Response.json(result);
  } catch (e) {
    return handleError(e);
  }
}

import { getServices } from "@/lib/factory";
import { handleError } from "../../../_http";

export async function POST(
  request: Request,
  { params }: { params: Promise<{ id: string }> },
) {
  try {
    const { id } = await params;
    const { export: exportSvc } = getServices();
