    if (!targetDir) {
      return new Response(
        JSON.stringify({ error: "invalid_input", message: "targetDir required" }),
        { status: 400, headers: { "content-type": "application/json" } },
      );
    }
    const result = await exportSvc.exportTo(id, targetDir);
    return Response.json(result);
  } catch (e) {
    return handleError(e);
  }
}

import { getServices } from "@/lib/factory";
import { handleError } from "../../../../../_http";

export async function POST(
  request: Request,
  { params }: { params: Promise<{ id: string; cid: string }> },
) {
  try {
    const { id, cid } = await params;
    const { runner } = getServices();
    const url = new URL(request.url);
    const qCount = url.searchParams.get("count");
    let body: Record<string, unknown> = {};
    try {
      body = await request.json();
    } catch {}
    const count = Number(qCount ?? body?.count ?? 1);
    if (!Number.isFinite(count) || count < 1 || count > 16) {
      return new Response(
        JSON.stringify({
          error: "invalid_input",
          message: "count must be 1..16",
        }),
        { status: 400, headers: { "content-type": "application/json" } },
      );
    }
    const result = await runner.retryChunk(id, cid, {
      count,
      params: (body?.params as Record<string, unknown>) ?? undefined,
    });
    return Response.json(result);
  } catch (e) {
    return handleError(e);
  }
}

import { createReadStream, statSync } from "fs";
import { Readable } from "stream";
import { getServices } from "@/lib/factory";
import { handleError } from "../../../../_http";

export async function GET(
  _req: Request,
  {
    params,
  }: {
    params: Promise<{ id: string; cid: string; takeId: string }>;
  },
) {
  try {
    const { id, cid, takeId } = await params;
    const { audio } = getServices();
    // special token "current" means "use selected take"
    const resolvedTake = takeId === "current" ? undefined : takeId;
    const filePath = await audio.getTakeFile(id, cid, resolvedTake);
    const stat = statSync(filePath);
    const stream = Readable.toWeb(
      createReadStream(filePath),
    ) as unknown as ReadableStream<Uint8Array>;
    return new Response(stream, {
      headers: {
        "Content-Type": "audio/wav",
        "Content-Length": String(stat.size),
        "Accept-Ranges": "bytes",
        "Cache-Control": "no-store",
      },
    });
  } catch (e) {
    return handleError(e);
  }
}

